// 每3關一組，size+2；每組前2關easy後1關hard
// singleton 數量決定難度：越多越簡單
function getLevelConfig(idx) {
  // 前20關（idx 0-19）：每5關一循環
  //   關1-3：5×5 新手  關4：7×7 進階  關5：11×11 挑戰
  // 20關後（idx >= 20）：每5關一循環，棋盤升級
  //   關1：5×5 新手  關2-4：7×7 進階  關5：11×11 挑戰

  const pos = idx % 5;
  const cycle = Math.floor(idx / 5);
  const isLate = idx >= 20;  // 20關後

  if (!isLate) {
    // 前20關
    if (pos <= 2) {
      const singletons = Math.max(3, 5 - pos - cycle);
      return { size: 5, singletons, diff: 0 };
    } else if (pos === 3) {
      const singletons = Math.max(3, 6 - cycle);
      return { size: 7, singletons, diff: 1 };
    } else {
      const singletons = Math.max(5, 9 - cycle);
      return { size: 11, singletons, diff: -1 };
    }
  } else {
    // 20關後
    const lateCycle = Math.floor((idx - 20) / 5);
    if (pos === 0) {
      // 關1：5×5 新手
      const singletons = Math.max(2, 4 - lateCycle);
      return { size: 5, singletons, diff: 0 };
    } else if (pos <= 3) {
      // 關2-4：7×7 進階
      const singletons = Math.max(3, 6 - pos - lateCycle);
      return { size: 7, singletons, diff: 1 };
    } else {
      // 關5：11×11 挑戰
      const singletons = Math.max(4, 7 - lateCycle);
      return { size: 11, singletons, diff: -1 };
    }
  }
}

function shuffle(arr) {
  const a = [...arr];
  for (let i = a.length-1; i > 0; i--) {
    const j = Math.floor(Math.random()*(i+1));
    [a[i],a[j]] = [a[j],a[i]];
  }
  return a;
}

function isValid(grid, row, col, size) {
  for (let c=0; c<size; c++) if (c!==col && grid[row][c]===1) return false;
  for (let r=0; r<size; r++) if (r!==row && grid[r][col]===1) return false;
  for (let dr=-1; dr<=1; dr++)
    for (let dc=-1; dc<=1; dc++) {
      if (dr===0&&dc===0) continue;
      const nr=row+dr, nc=col+dc;
      if (nr>=0&&nr<size&&nc>=0&&nc<size&&grid[nr][nc]===1) return false;
    }
  return true;
}

function genSolution(size) {
  const grid = Array.from({length:size},()=>Array(size).fill(0));
  function bt(row) {
    if (row===size) return true;
    for (const col of shuffle([...Array(size).keys()])) {
      grid[row][col]=1;
      if (isValid(grid,row,col,size)&&bt(row+1)) return true;
      grid[row][col]=0;
    }
    return false;
  }
  bt(0);
  return grid;
}

// 核心：n_singletons 個顏色只有1格（保證推理突破口）
// 其餘顏色 BFS 擴散填滿棋盤
function genColorMap(solution, size, nSingletons) {
  const cats = [];
  for (let r=0;r<size;r++) for (let c=0;c<size;c++) if (solution[r][c]===1) cats.push([r,c]);
  const singletonIdx = new Set(shuffle([...Array(cats.length).keys()]).slice(0,nSingletons));
  const cm = Array.from({length:size},()=>Array(size).fill(-1));
  cats.forEach(([r,c],i) => { cm[r][c]=i+1; });

  // singleton 顏色：只有貓那1格，不擴張（這是給玩家的提示！）
  // 非singleton 顏色：平衡擴張，每色盡量相同格數
  const nonSingletonCount = size - nSingletons;
  const totalNonSingletonCells = size*size - nSingletons; // singleton 各佔1格
  const target = nonSingletonCount > 0
    ? Math.floor(totalNonSingletonCells / nonSingletonCount)
    : 0;

  const colorCount = Array(size+1).fill(0);
  cats.forEach(([r,c],i) => { colorCount[i+1]=1; });

  // 只有非singleton才進 BFS queue
  const queues = cats.map(([r,c],i) => singletonIdx.has(i) ? [] : [[r,c]]);
  let totalFilled = cats.length;
  const totalCells = size*size;

  while (totalFilled < totalCells) {
    const order = shuffle([...Array(size).keys()])
      .sort((a,b) => colorCount[a+1] - colorCount[b+1]);
    let anyExpanded = false;
    for (const i of order) {
      if (singletonIdx.has(i)) continue; // singleton 跳過
      if (colorCount[i+1] >= target + 2) continue;
      const q = queues[i];
      if (q.length === 0) continue;
      const [r,c] = q.shift();
      for (const [dr,dc] of shuffle([[0,1],[0,-1],[1,0],[-1,0]])) {
        const nr=r+dr, nc=c+dc;
        if (nr>=0&&nr<size&&nc>=0&&nc<size&&cm[nr][nc]===-1) {
          cm[nr][nc]=i+1;
          colorCount[i+1]++;
          q.push([nr,nc]);
          totalFilled++;
          anyExpanded=true;
          break;
        }
      }
    }
    if (!anyExpanded) break;
  }

  // 填剩餘
  let changed=true;
  while (changed) {
    changed=false;
    for (let r=0;r<size;r++) for (let c=0;c<size;c++) if (cm[r][c]===-1)
      for (const [dr,dc] of [[0,1],[0,-1],[1,0],[-1,0]]) {
        const nr=r+dr,nc=c+dc;
        if (nr>=0&&nr<size&&nc>=0&&nc<size&&cm[nr][nc]!==-1) { cm[r][c]=cm[nr][nc]; changed=true; break; }
      }
  }
  return cm;
}

// 邏輯可解驗證
function canSolve(cm, size) {
  const cand = Array.from({length:size},()=>Array(size).fill(true));
  const placedRow = Array(size).fill(null);
  const placedCol = Array(size).fill(null);
  let count=0;
  const elim=(r,c)=>{ cand[r][c]=false; };
  const place=(r,c)=>{
    if (placedRow[r]!==null) return;
    placedRow[r]=c; placedCol[c]=r; count++;
    for (let i=0;i<size;i++) { elim(r,i); elim(i,c); }
    for (let dr=-1;dr<=1;dr++) for (let dc=-1;dc<=1;dc++) {
      const nr=r+dr,nc=c+dc;
      if (nr>=0&&nr<size&&nc>=0&&nc<size) elim(nr,nc);
    }
  };
  const colorDone=(col)=>placedRow.some((c,r)=>c!==null&&cm[r][c]===col);
  let progress=true;
  while (progress&&count<size) {
    progress=false;
    for (let color=1;color<=size;color++) {
      if (colorDone(color)) continue;
      const cells=[];
      for (let r=0;r<size;r++) for (let c=0;c<size;c++)
        if (cm[r][c]===color&&cand[r][c]&&placedRow[r]===null) cells.push([r,c]);
      if (cells.length===0) return false;
      if (cells.length===1) { place(...cells[0]); progress=true; }
    }
    for (let r=0;r<size;r++) {
      if (placedRow[r]!==null) continue;
      const cells=[...Array(size).keys()].filter(c=>cand[r][c]);
      if (cells.length===1) { place(r,cells[0]); progress=true; }
    }
    for (let c=0;c<size;c++) {
      if (placedCol[c]!==null) continue;
      const cells=[...Array(size).keys()].filter(r=>cand[r][c]&&placedRow[r]===null);
      if (cells.length===1) { place(cells[0],c); progress=true; }
    }
  }
  return count===size;
}

function genPuzzle(size, nSingletons) {
  for (let t=0;t<500;t++) {
    const sol=genSolution(size);
    const cm=genColorMap(sol,size,nSingletons);
    if (canSolve(cm,size)) return {sol,cm};
  }
  const sol=genSolution(size);
  return {sol, cm:genColorMap(sol,size,nSingletons)};
}


// ─── 音效系統 ─────────────────────────────────────────────────────────────
const CAT_MEOW_B64 = "data:audio/mp3;base64,";

const AudioCtx = typeof window !== 'undefined'
  ? (window.AudioContext || window.webkitAudioContext) : null;
let _ctx = null;

function getCtx() {
  if (!_ctx && AudioCtx) _ctx = new AudioCtx();
  if (_ctx && _ctx.state === 'suspended') _ctx.resume();
  return _ctx;
}

// 低通濾波輸出（讓合成音效更圓潤）
function makeOut(ctx, cutoff=1800) {
  const f = ctx.createBiquadFilter();
  f.type='lowpass'; f.frequency.value=cutoff; f.Q.value=0.7;
  f.connect(ctx.destination);
  return f;
}

function playOscF(freq, type, dur, vol, t, cutoff=1800) {
  const ctx=getCtx(); if(!ctx) return;
  const osc=ctx.createOscillator(), g=ctx.createGain(), out=makeOut(ctx,cutoff);
  osc.connect(g); g.connect(out);
  osc.type=type; osc.frequency.value=freq;
  g.gain.setValueAtTime(0,t);
  g.gain.linearRampToValueAtTime(vol,t+0.02);
  g.gain.exponentialRampToValueAtTime(0.001,t+dur);
  osc.start(t); osc.stop(t+dur+0.05);
}

// 解碼並快取 base64 音效
let _meowBuffer = null;
async function getMeowBuffer() {
  if (_meowBuffer) return _meowBuffer;
  const ctx = getCtx(); if (!ctx) return null;
  const b64 = CAT_MEOW_B64.split(',')[1];
  const bin = atob(b64);
  const arr = new Uint8Array(bin.length);
  for (let i=0; i<bin.length; i++) arr[i] = bin.charCodeAt(i);
  try {
    _meowBuffer = await ctx.decodeAudioData(arr.buffer);
  } catch(e) { console.warn('meow decode failed', e); }
  return _meowBuffer;
}
// 預先解碼（頁面載入後靜默執行）
setTimeout(()=>getMeowBuffer(), 500);

// 播放真實貓叫（用 Web Audio API，支援 playbackRate）
async function playCatMeow(rate=1.0, vol=1.0) {
  const ctx = getCtx(); if (!ctx) return;
  const buf = await getMeowBuffer(); if (!buf) return;
  const src = ctx.createBufferSource();
  const gain = ctx.createGain();
  src.connect(gain); gain.connect(ctx.destination);
  src.buffer = buf;
  src.playbackRate.value = rate;
  gain.gain.value = vol;
  src.start();
}

// ✕ 標記叉叉：輕快短透「噗」
function sfxMark() {
  const ctx=getCtx(); if(!ctx) return;
  const t=ctx.currentTime;
  playOscF(320,'sine',0.1,0.2,t,1200);
  playOscF(480,'sine',0.06,0.08,t,900);
}

// 🐱 找到貓：真實貓叫（正常音高）
function sfxFound() {
  playCatMeow(1.0, 0.9);
}

// 💥 答錯：真實貓叫（低音調，像被驚嚇）
function sfxWrong() {
  playCatMeow(0.72, 0.85);
}

// 🎉 過關：三聲漸高貓叫
function sfxWin() {
  playCatMeow(0.95, 0.8);
  setTimeout(()=>playCatMeow(1.1, 0.85), 280);
  setTimeout(()=>playCatMeow(1.3, 0.9), 560);
}

// ─── 背景音樂：C大調五聲音階，固定節奏 ──────────────────────────────────
let bgNodes = [];
let bgPlaying = false;
let bgLoopTimer = null;

// C大調五聲音階（Do Re Mi Sol La），兩個八度
// 261=C4, 293=D4, 329=E4, 392=G4, 440=A4, 523=C5, 587=D5, 659=E5
const PENTATONIC = [261, 293, 329, 392, 440, 523, 587, 659, 523, 440];

// 旋律：[音階index, 拍數]，-1=休止
// 固定節奏，每拍 0.35 秒，輕快但不快
const MELODY = [
  [4,1],[5,1],[6,1],[4,1],
  [5,1],[7,2],[-1,1],
  [4,1],[3,1],[2,1],[3,1],
  [4,3],[-1,1],
  [5,1],[6,1],[7,1],[8,1],
  [9,2],[7,1],[-1,1],
  [6,1],[5,1],[4,1],[5,1],
  [6,3],[-1,1],
  [2,1],[3,1],[4,1],[3,1],
  [2,1],[0,2],[-1,1],
  [4,1],[5,1],[6,1],[4,1],
  [5,1],[7,3],[-1,1],
];

const BEAT = 0.36;  // 秒/拍，固定不抖動

function playNote(ctx, freq, startT, dur, vol=0.08) {
  const out = makeOut(ctx, 2800);
  const osc = ctx.createOscillator();
  const gain = ctx.createGain();
  osc.connect(gain); gain.connect(out);
  osc.type = 'sine';
  osc.frequency.value = freq;
  gain.gain.setValueAtTime(0, startT);
  gain.gain.linearRampToValueAtTime(vol, startT + 0.012);
  gain.gain.setValueAtTime(vol * 0.7, startT + 0.04);
  gain.gain.exponentialRampToValueAtTime(0.001, startT + dur * 0.85);
  osc.start(startT); osc.stop(startT + dur);
  bgNodes.push(osc);
  // 高泛音（音樂盒金屬感）
  const osc2 = ctx.createOscillator();
  const g2 = ctx.createGain();
  osc2.connect(g2); g2.connect(out);
  osc2.type = 'sine';
  osc2.frequency.value = freq * 2.0;
  g2.gain.setValueAtTime(0, startT);
  g2.gain.linearRampToValueAtTime(vol * 0.15, startT + 0.01);
  g2.gain.exponentialRampToValueAtTime(0.001, startT + 0.2);
  osc2.start(startT); osc2.stop(startT + 0.25);
  bgNodes.push(osc2);
}

function scheduleMusicBox(startT) {
  const ctx = getCtx(); if (!ctx) return startT;
  let t = startT;
  MELODY.forEach(([idx, beats]) => {
    const dur = beats * BEAT;
    if (idx >= 0) {
      playNote(ctx, PENTATONIC[idx], t, dur);
    }
    t += dur;
  });
  return t;
}

function startBgMusic(muted) {
  if (bgPlaying || muted) return;
  bgPlaying = true;
  const ctx = getCtx(); if (!ctx) return;
  let t = ctx.currentTime + 0.3;
  t = scheduleMusicBox(t);
  const totalDur = MELODY.reduce((s,[,b])=>s+b, 0) * BEAT * 1000;
  function scheduleLoop() {
    if (!bgPlaying) return;
    const c = getCtx(); if (!c) return;
    let t2 = c.currentTime + 0.1;
    scheduleMusicBox(t2);
    bgLoopTimer = setTimeout(scheduleLoop, totalDur);
  }
  bgLoopTimer = setTimeout(scheduleLoop, totalDur);
}

function stopBgMusic() {
  bgPlaying = false;
  if (bgLoopTimer) { clearTimeout(bgLoopTimer); bgLoopTimer = null; }
  bgNodes.forEach(n => { if (n?.stop) { try { n.stop(); } catch {} } });
  bgNodes = [];
}

const STYLES=`
  @import url('https://fonts.googleapis.com/css2?family=Nunito:wght@700;800;900&display=swap');
  *{box-sizing:border-box;-webkit-tap-highlight-color:transparent;touch-action:none;}
  @keyframes catReveal{0%{transform:scale(0) rotate(-15deg);opacity:0}60%{transform:scale(1.35) rotate(4deg);opacity:1}100%{transform:scale(1) rotate(0);opacity:1}}
  @keyframes wrongShake{0%,100%{transform:translateX(0) scale(1)}25%,75%{transform:translateX(-6px) scale(0.9)}50%{transform:translateX(6px) scale(0.9)}}
  @keyframes floatCat{0%,100%{transform:translateY(0)}50%{transform:translateY(-6px)}}
  @keyframes slideUp{from{transform:translateY(28px);opacity:0}to{transform:translateY(0);opacity:1}}
  @keyframes lifeLost{0%,100%{transform:scale(1)}40%{transform:scale(1.6);filter:hue-rotate(120deg) brightness(1.3)}}
  @keyframes popIn{0%{transform:scale(0.85);opacity:0}100%{transform:scale(1);opacity:1}}
  .cell-reveal{animation:catReveal 0.4s cubic-bezier(0.34,1.56,0.64,1) forwards}
  .cell-wrong{animation:wrongShake 0.45s ease}
  .cat-float{animation:floatCat 2.5s ease-in-out infinite}
  .modal-in{animation:slideUp 0.3s ease forwards}
  .life-lost{animation:lifeLost 0.45s ease}
  .pop-in{animation:popIn 0.25s ease forwards}
  .btn{cursor:pointer;font-family:'Nunito',sans-serif;font-weight:900;border:none;transition:transform 0.12s}
  .btn:active{transform:scale(0.93)!important}
`;

export default function CatSudoku() {
  const savedLevel=(()=>{try{return parseInt(localStorage.getItem(STORAGE_KEY)||"0");}catch{return 0;}})();
  const tutorialDone=(()=>{try{return localStorage.getItem("ajimomomo_tutorial")==="1";}catch{return false;}})();
  const [unlockedLevels,setUnlockedLevels]=useState(savedLevel+1);
  const [screen,setScreen]=useState("select");
  const [currentLevel,setCurrentLevel]=useState(savedLevel);
  const [solution,setSolution]=useState([]);
  const [colorMap,setColorMap]=useState([]);
  const [board,setBoard]=useState([]);
  const [lives,setLives]=useState(3);
  const [wrongCell,setWrongCell]=useState(null);
  const [shakingLife,setShakingLife]=useState(null);
  const [gameStatus,setGameStatus]=useState("playing");
  const [revealAll,setRevealAll]=useState(false);
  const [catAssign,setCatAssign]=useState({});
  const [lastTap,setLastTap]=useState({});
  const [isGenerating,setIsGenerating]=useState(false);
  const [showTutorial,setShowTutorial]=useState(!tutorialDone);
  const [muted,setMuted]=useState(false);
  const mutedRef=useRef(false);
  const isDragging=useRef(false);
  const draggedCells=useRef(new Set());
  const dragMode=useRef(null);
  const allCats=[CAT_ORANGE,CAT_TABBY];

  const initLevel=useCallback((lvlIdx)=>{
    setIsGenerating(true);
    setTimeout(()=>{
      const {size,singletons}=getLevelConfig(lvlIdx);
      const {sol,cm}=genPuzzle(size,singletons);
      const assign={};
      for(let r=0;r<size;r++) for(let c=0;c<size;c++)
        if(sol[r][c]===1) assign[`${r},${c}`]=allCats[Math.floor(Math.random()*allCats.length)];
      setSolution(sol); setColorMap(cm);
      setBoard(Array.from({length:size},()=>Array(size).fill(0)));
      setLives(3); setWrongCell(null); setShakingLife(null);
      setGameStatus("playing"); setRevealAll(false); setLastTap({});
      setCatAssign(assign); setCurrentLevel(lvlIdx);
      setIsGenerating(false); setScreen("game");
      if (!mutedRef.current) setTimeout(()=>startBgMusic(mutedRef.current),100);
    },60);
  },[]);

  const handleClick=(r,c)=>{
    getCtx(); // 確保 AudioContext 已啟動
    if(gameStatus!=="playing"||board[r][c]===2) return;
    const key=`${r},${c}`,now=Date.now(),prev=lastTap[key];
    if(prev&&now-prev<400){
      setLastTap({});
      if(solution[r][c]===1){
        sfxFound();
        const nb=board.map(row=>[...row]); nb[r][c]=2; setBoard(nb);
        const all=solution.every((row,ri)=>row.every((v,ci)=>v!==1||nb[ri][ci]===2));
        if(all){ sfxWin(); setGameStatus("won"); setUnlockedLevels(u=>Math.max(u,currentLevel+2)); try{localStorage.setItem(STORAGE_KEY,String(currentLevel+1));}catch{} }
      } else {
        sfxWrong();
        setWrongCell(key); const nl=lives-1; setShakingLife(nl);
        setTimeout(()=>{setWrongCell(null);setShakingLife(null);},600);
        setLives(nl); if(nl<=0){setGameStatus("lost");setRevealAll(true);}
      }
    } else { setLastTap(p=>({...p,[key]:now})); }
  };

  const startDrag=(r,c)=>{
    getCtx(); // 確保 AudioContext 已啟動
    if(gameStatus!=="playing"||board[r][c]===2) return;
    isDragging.current=true; draggedCells.current=new Set([`${r},${c}`]);
    dragMode.current=board[r][c]===1?"unmark":"mark";
    if(dragMode.current==="mark") sfxMark();
    setBoard(prev=>{const nb=prev.map(row=>[...row]);nb[r][c]=dragMode.current==="mark"?1:0;return nb;});
  };
  const enterCell=(r,c)=>{
    if(!isDragging.current||gameStatus!=="playing"||board[r][c]===2) return;
    const key=`${r},${c}`; if(draggedCells.current.has(key)) return;
    draggedCells.current.add(key);
    setBoard(prev=>{const nb=prev.map(row=>[...row]);if(nb[r][c]!==2)nb[r][c]=dragMode.current==="mark"?1:0;return nb;});
  };
  const endDrag=()=>{isDragging.current=false;draggedCells.current=new Set();dragMode.current=null;};

  const toggleMute=useCallback(()=>{
    setMuted(m=>{
      const next=!m; mutedRef.current=next;
      if(next) stopBgMusic(); else startBgMusic(false);
      return next;
    });
  },[]);

  const {size}=getLevelConfig(currentLevel);
  const cellSize=size<=5?58:size<=7?46:size<=9?38:size<=11?30:26;

  if(screen==="select"){
    const lvlIdx=unlockedLevels-1;
    const {size:sz}=getLevelConfig(lvlIdx);
    const {diff:lvlDiff}=getLevelConfig(lvlIdx);
    const diff=lvlDiff===-1?'⭐ 挑戰關':lvlDiff===1?'🔥 進階':'🌱 新手';
    return(
      <div style={{minHeight:"100vh",background:"linear-gradient(160deg,#FFF9F0,#FFEEDD)",fontFamily:"'Nunito',sans-serif",display:"flex",flexDirection:"column",alignItems:"center",justifyContent:"center",padding:"32px 20px"}}>
        <style>{STYLES}</style>
        <div style={{display:"flex",gap:16,marginBottom:14}}>
          <img src={CAT_ORANGE} className="cat-float" style={{width:72,height:72,borderRadius:"50%",border:"3px solid #FFCBA8"}} alt="阿吉"/>
          <img src={CAT_TABBY} className="cat-float" style={{width:72,height:72,borderRadius:"50%",border:"3px solid #FFCBA8",animationDelay:"0.4s"}} alt="毛毛"/>
        </div>
        <h1 style={{margin:"0 0 4px",fontSize:26,fontWeight:900,color:"#FF6B35",letterSpacing:1}}>找找阿吉與毛毛</h1>
        <p style={{margin:"0 0 32px",color:"#CCA080",fontSize:13}}>雙擊格子找出躲藏的貓咪！</p>
        <div className="pop-in" style={{width:"100%",maxWidth:320}}>
          <button className="btn" onClick={()=>initLevel(lvlIdx)} style={{width:"100%",display:"flex",alignItems:"center",justifyContent:"space-between",padding:"18px 20px",background:"white",border:"2.5px solid #FFE4D0",borderRadius:18,boxShadow:"0 4px 20px rgba(255,107,53,0.12)"}}>
            <div style={{display:"flex",alignItems:"center",gap:14}}>
              <div style={{width:44,height:44,borderRadius:12,background:"linear-gradient(135deg,#FF6B35,#FFAA6C)",display:"flex",alignItems:"center",justifyContent:"center",color:"white",fontSize:18,fontWeight:900}}>{lvlIdx+1}</div>
              <div style={{textAlign:"left"}}>
                <div style={{fontSize:16,fontWeight:900,color:"#333"}}>第 {lvlIdx+1} 關</div>
                <div style={{fontSize:12,color:"#BBB",marginTop:2}}>{sz}×{sz} 棋盤 · {diff}</div>
              </div>
            </div>
            <span style={{color:"#FF9A6C",fontSize:24,fontWeight:900}}>›</span>
          </button>
          {lvlIdx>0&&<button className="btn" onClick={()=>initLevel(0)} style={{width:"100%",marginTop:10,padding:"12px 20px",background:"transparent",border:"2px solid #FFE4D0",borderRadius:14,color:"#CCA080",fontSize:13}}>從第一關開始</button>}
        </div>
        {lvlIdx>0&&<div style={{marginTop:20,fontSize:12,color:"#CCA080"}}>已完成 {lvlIdx} 關 🐾</div>}
      </div>
    );
  }

  if(isGenerating) return(
    <div style={{minHeight:"100vh",background:"linear-gradient(160deg,#FFF9F0,#FFEEDD)",display:"flex",flexDirection:"column",alignItems:"center",justifyContent:"center",fontFamily:"'Nunito',sans-serif"}}>
      <style>{STYLES}</style>
      <div className="cat-float" style={{display:"flex",gap:12,marginBottom:16}}>
        <img src={CAT_ORANGE} style={{width:56,height:56,borderRadius:"50%",border:"3px solid #FFCBA8"}} alt="阿吉"/>
        <img src={CAT_TABBY}  style={{width:56,height:56,borderRadius:"50%",border:"3px solid #FFCBA8"}} alt="毛毛"/>
      </div>
      <div style={{color:"#FF9A6C",fontWeight:900,fontSize:15}}>阿吉和毛毛藏好了嗎⋯</div>
    </div>
  );

  return(
    <div style={{minHeight:"100vh",background:"linear-gradient(160deg,#FFF9F0,#FFEEDD)",fontFamily:"'Nunito',sans-serif",display:"flex",flexDirection:"column",alignItems:"center",userSelect:"none",WebkitUserSelect:"none"}}
      onMouseUp={endDrag} onTouchEnd={endDrag}>
      <style>{STYLES}</style>
      <div style={{width:"100%",maxWidth:420,padding:"14px 16px 0",display:"flex",alignItems:"center",justifyContent:"space-between"}}>
        <button className="btn" onClick={()=>setScreen("select")} style={{background:"none",color:"#FF9A6C",fontSize:26,padding:4}}>‹</button>
        <div style={{textAlign:"center"}}>
          <div style={{fontSize:15,fontWeight:900,color:"#FF6B35"}}>第 {currentLevel+1} 關</div>
          <div style={{fontSize:11,color:"#CCA080"}}>{size}×{size} · 找出 {size} 隻貓咪</div>
        </div>
        <div style={{display:"flex",alignItems:"center",gap:2}}>
          <button className="btn" onClick={toggleMute} style={{background:"none",color:"#FF9A6C",fontSize:18,padding:4}}>{muted?"🔇":"🔊"}</button>
          <button className="btn" onClick={()=>initLevel(currentLevel)} style={{background:"none",color:"#FF9A6C",fontSize:20,padding:4}}>↺</button>
        </div>
      </div>
      <div style={{display:"flex",gap:10,margin:"12px 0 4px"}}>
        {[0,1,2].map(i=><span key={i} className={shakingLife===i?"life-lost":""} style={{fontSize:26,filter:i<lives?"none":"grayscale(1) opacity(0.25)",transition:"filter 0.4s"}}>🐾</span>)}
      </div>
      <div style={{fontSize:11,color:"#CCA080",marginBottom:12,textAlign:"center"}}>雙擊 = 找貓咪　滑動 = 標記空格</div>
      <div style={{display:"grid",gridTemplateColumns:`repeat(${size},${cellSize}px)`,gap:4,padding:14,background:"white",borderRadius:22,boxShadow:"0 8px 36px rgba(255,107,53,0.13)"}}>
        {colorMap.map((row,r)=>row.map((colorId,c)=>{
          const color=COLORS[(colorId-1)%COLORS.length];
          const state=board[r]?.[c]??0;
          const isFound=state===2,isMarked=state===1;
          const isWrong=wrongCell===`${r},${c}`;
          const showReveal=revealAll&&solution[r]?.[c]===1&&!isFound;
          const catImg=catAssign[`${r},${c}`];
          return(
            <div key={`${r}-${c}`} data-row={r} data-col={c}
              className={`${isFound?"cell-reveal":""} ${isWrong?"cell-wrong":""}`}
              style={{width:cellSize,height:cellSize,borderRadius:9,background:isFound?color.bg:`${color.bg}AA`,border:`1px solid rgba(0,0,0,0.08)`,display:"flex",alignItems:"center",justifyContent:"center",cursor:"pointer",position:"relative",boxShadow:isFound?`0 3px 12px ${color.bg}66`:"none",transition:"box-shadow 0.2s"}}
              onClick={()=>handleClick(r,c)}
              onMouseDown={()=>startDrag(r,c)}
              onMouseEnter={()=>enterCell(r,c)}
              onTouchStart={e=>{e.preventDefault();startDrag(r,c);}}
              onTouchMove={e=>{e.preventDefault();const t=e.touches[0];const el=document.elementFromPoint(t.clientX,t.clientY);if(el?.dataset?.row!==undefined)enterCell(parseInt(el.dataset.row),parseInt(el.dataset.col));}}
            >
              {!isFound&&!showReveal&&<div style={{width:cellSize*0.15,height:cellSize*0.15,borderRadius:"50%",background:color.bg,opacity:0.7,flexShrink:0}}/>}
              {isMarked&&!isFound&&<div style={{position:"absolute",fontSize:cellSize*0.56,fontWeight:900,color:"#111",opacity:0.85,lineHeight:1,textShadow:`0 1px 6px ${color.bg}88`}}>✕</div>}
              {isFound&&catImg&&<div className="cat-float"><img src={catImg} style={{width:cellSize*0.82,height:cellSize*0.82,borderRadius:"50%",border:"2px solid white",display:"block"}} alt="cat"/></div>}
              {showReveal&&catImg&&<img src={catImg} style={{width:cellSize*0.7,height:cellSize*0.7,borderRadius:"50%",opacity:0.4,display:"block"}} alt="cat"/>}
            </div>
          );
        }))}
      </div>
      <div style={{display:"flex",flexWrap:"wrap",justifyContent:"center",gap:5,marginTop:14,maxWidth:360,padding:"0 16px 32px"}}>
        {COLORS.slice(0,size).map((color,i)=>(
          <div key={i} style={{display:"flex",alignItems:"center",gap:4,padding:"3px 9px",borderRadius:20,background:`${color.bg}18`,border:`1px solid ${color.bg}44`,fontSize:11,color:"#888"}}>
            <div style={{width:7,height:7,borderRadius:"50%",background:color.bg}}/>{color.name}
          </div>
        ))}
      </div>


      {showTutorial&&(
        <div style={{position:"fixed",inset:0,background:"rgba(255,245,235,0.97)",display:"flex",flexDirection:"column",alignItems:"center",justifyContent:"center",zIndex:999,backdropFilter:"blur(12px)",padding:"24px 20px"}}>
          <div className="modal-in" style={{width:"100%",maxWidth:340,textAlign:"center"}}>
            <div style={{display:"flex",gap:12,justifyContent:"center",marginBottom:8}}>
              <img src={CAT_ORANGE} className="cat-float" style={{width:56,height:56,borderRadius:"50%",border:"3px solid #FFCBA8"}} alt="ajji"/>
              <img src={CAT_TABBY} className="cat-float" style={{width:56,height:56,borderRadius:"50%",border:"3px solid #FFCBA8",animationDelay:"0.4s"}} alt="momo"/>
            </div>
            <div style={{fontSize:20,fontWeight:900,color:"#FF6B35",marginBottom:4}}>怎麼找到阿吉和毛毛？</div>
            <div style={{fontSize:12,color:"#CCA080",marginBottom:20}}>第一次玩，先看一下規則！</div>
            <div style={{display:"flex",flexDirection:"column",gap:10,marginBottom:22,textAlign:"left"}}>
              <div style={{background:"white",borderRadius:14,padding:"12px 14px",border:"2px solid #FFE4D0",display:"flex",alignItems:"flex-start",gap:10}}>
                <div style={{fontSize:22,flexShrink:0}}>🎨</div>
                <div>
                  <div style={{fontSize:13,fontWeight:900,color:"#FF6B35",marginBottom:2}}>每種顏色藏一隻貓</div>
                  <div style={{fontSize:12,color:"#888",lineHeight:1.5}}>棋盤分成好幾個顏色區塊，每個顏色裡剛好藏著一隻貓咪。</div>
                </div>
              </div>
              <div style={{background:"white",borderRadius:14,padding:"12px 14px",border:"2px solid #FFE4D0",display:"flex",alignItems:"flex-start",gap:10}}>
                <div style={{fontSize:22,flexShrink:0}}>📐</div>
                <div>
                  <div style={{fontSize:13,fontWeight:900,color:"#FF6B35",marginBottom:2}}>每行每列恰好一隻，不能相鄰</div>
                  <div style={{fontSize:12,color:"#888",lineHeight:1.5}}>每行每列只有一隻貓，貓和貓之間連斜角都不能緊鄰。</div>
                </div>
              </div>
              <div style={{background:"white",borderRadius:14,padding:"12px 14px",border:"2px solid #FFE4D0",display:"flex",alignItems:"flex-start",gap:10}}>
                <div style={{fontSize:22,flexShrink:0}}>👆</div>
                <div>
                  <div style={{fontSize:13,fontWeight:900,color:"#FF6B35",marginBottom:2}}>雙擊找貓　滑動標記✕</div>
                  <div style={{fontSize:12,color:"#888",lineHeight:1.5}}>確定是貓就雙擊那格；確定不是就滑動標記叉叉排除。</div>
                </div>
              </div>
              <div style={{background:"white",borderRadius:14,padding:"12px 14px",border:"2px solid #FFE4D0",display:"flex",alignItems:"flex-start",gap:10}}>
                <div style={{fontSize:22,flexShrink:0}}>🐾</div>
                <div>
                  <div style={{fontSize:13,fontWeight:900,color:"#FF6B35",marginBottom:2}}>3 條命，答錯扣一條</div>
                  <div style={{fontSize:12,color:"#888",lineHeight:1.5}}>雙擊錯誤的格子會扣命，三條都用完貓咪就跑掉了！</div>
                </div>
              </div>
            </div>
            <button className="btn" onClick={()=>{setShowTutorial(false);try{localStorage.setItem("ajimomomo_tutorial","1");}catch{}}} style={{width:"100%",padding:"14px",borderRadius:16,background:"linear-gradient(135deg,#FF6B35,#FFAA6C)",color:"white",fontSize:15,fontWeight:900,boxShadow:"0 6px 20px rgba(255,107,53,0.35)"}}>
              我知道了，開始找貓！🐱
            </button>
          </div>
        </div>
      )}

      {gameStatus==="won"&&(
        <div style={{position:"fixed",inset:0,background:"rgba(255,245,235,0.94)",display:"flex",flexDirection:"column",alignItems:"center",justifyContent:"center",zIndex:99,backdropFilter:"blur(10px)"}}>
          <div className="modal-in" style={{textAlign:"center"}}>
            <div style={{display:"flex",gap:14,justifyContent:"center",marginBottom:10}}>
              <img src={CAT_ORANGE} className="cat-float" style={{width:68,height:68,borderRadius:"50%",border:"3px solid #FFCBA8"}} alt="阿吉"/>
              <img src={CAT_TABBY} className="cat-float" style={{width:68,height:68,borderRadius:"50%",border:"3px solid #FFCBA8",animationDelay:"0.3s"}} alt="毛毛"/>
            </div>
            <div style={{fontSize:26,fontWeight:900,color:"#FF6B35",margin:"4px 0"}}>找到啦！！</div>
            <div style={{fontSize:14,color:"#CCA080",marginBottom:28}}>阿吉和毛毛都現身了 ✨</div>
            <div style={{display:"flex",gap:10,justifyContent:"center"}}>
              <button className="btn" onClick={()=>initLevel(currentLevel)} style={{padding:"12px 20px",borderRadius:14,border:"2px solid #FFD4B0",background:"white",color:"#FF6B35",fontSize:14}}>再玩一次</button>
              <button className="btn" onClick={()=>initLevel(currentLevel+1)} style={{padding:"12px 22px",borderRadius:14,background:"linear-gradient(135deg,#FF6B35,#FFAA6C)",color:"white",fontSize:14,boxShadow:"0 6px 20px rgba(255,107,53,0.35)"}}>下一關 ›</button>
            </div>
          </div>
        </div>
      )}

      {gameStatus==="lost"&&(
        <div style={{position:"fixed",inset:0,background:"rgba(20,10,10,0.88)",display:"flex",flexDirection:"column",alignItems:"center",justifyContent:"center",zIndex:99,backdropFilter:"blur(10px)"}}>
          <div className="modal-in" style={{textAlign:"center"}}>
            <div style={{fontSize:62,marginBottom:8}}>😿</div>
            <div style={{fontSize:24,fontWeight:900,color:"#FF8787",margin:"4px 0"}}>阿吉跟毛毛跑掉了</div>
            <div style={{fontSize:13,color:"#777",marginBottom:28}}>三條命都用完了</div>
            <div style={{display:"flex",gap:10,justifyContent:"center"}}>
              <button className="btn" onClick={()=>setScreen("select")} style={{padding:"12px 20px",borderRadius:14,border:"2px solid #444",background:"transparent",color:"#AAA",fontSize:14}}>返回</button>
              <button className="btn" onClick={()=>initLevel(currentLevel)} style={{padding:"12px 22px",borderRadius:14,background:"linear-gradient(135deg,#FF6B35,#FFAA6C)",color:"white",fontSize:14,boxShadow:"0 6px 20px rgba(255,107,53,0.4)"}}>再試一次 ↺</button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}
